@WebService(serviceName = "OrderProcessingService", targetNamespace = "http://soap.ecommerce.com/")
@SOAPBinding(style = Style.DOCUMENT)
public class OrderProcessingService {

    @WebMethod(operationName = "processOrder")
    public OrderResponse processOrder(@WebParam(name = "orderRequest") OrderRequest orderRequest) {
        try {
            if (orderRequest == null) {
                return createErrorResponse("Order request cannot be null");
            }

            if (orderRequest.getCustomerId() == null || orderRequest.getCustomerId().trim().isEmpty()) {
                return createErrorResponse("Customer ID is required");
            }

            if (orderRequest.getOrderItems() == null || orderRequest.getOrderItems().isEmpty()) {
                return createErrorResponse("Order must contain at least one item");
            }

            BigDecimal totalAmount = calculateTotalAmount(orderRequest.getOrderItems());

            if (totalAmount.compareTo(BigDecimal.ZERO) <= 0) {
                return createErrorResponse("Order total must be greater than zero");
            }

            String orderId = generateOrderId();
            Date orderDate = new Date();
            int itemCount = calculateTotalItemCount(orderRequest.getOrderItems());

            processOrderInternally(orderId, orderRequest, totalAmount);

            OrderResponse response = new OrderResponse(
                orderId,
                "SUCCESS",
                "Order processed successfully",
                totalAmount,
                orderDate,
                itemCount
            );

            return response;

        } catch (Exception e) {
            return createErrorResponse("Error processing order: " + e.getMessage());
        }
    }

    @WebMethod(operationName = "getOrderTotal")
    public BigDecimal getOrderTotal(@WebParam(name = "orderItems") List<OrderItem> orderItems) {
        if (orderItems == null || orderItems.isEmpty()) {
            return BigDecimal.ZERO;
        }
        return calculateTotalAmount(orderItems);
    }

    @WebMethod(operationName = "validateOrder")
    public boolean validateOrder(@WebParam(name = "orderRequest") OrderRequest orderRequest) {
        if (orderRequest == null) {
            return false;
        }

        if (orderRequest.getCustomerId() == null || orderRequest.getCustomerId().trim().isEmpty()) {
            return false;
        }

        if (orderRequest.getOrderItems() == null || orderRequest.getOrderItems().isEmpty()) {
            return false;
        }

        for (OrderItem item : orderRequest.getOrderItems()) {
            if (item.getQuantity() <= 0) {
                return false;
            }
            if (item.getUnitPrice() == null || item.getUnitPrice().compareTo(BigDecimal.ZERO) <= 0) {
                return false;
            }
        }

        return true;
    }

    private BigDecimal calculateTotalAmount(List<OrderItem> orderItems) {
        BigDecimal total = BigDecimal.ZERO;
        
        for (OrderItem item : orderItems) {
            if (item.getQuantity() > 0 && item.getUnitPrice() != null) {
                BigDecimal lineTotal = item.getUnitPrice()
                    .multiply(new BigDecimal(item.getQuantity()))
                    .setScale(2, RoundingMode.HALF_UP);
                total = total.add(lineTotal);
            }
        }
        
        return total.setScale(2, RoundingMode.HALF_UP);
    }

    private int calculateTotalItemCount(List<OrderItem> orderItems) {
        int count = 0;
        for (OrderItem item : orderItems) {
            count += item.getQuantity();
        }
        return count;
    }

    private String generateOrderId() {
        return "ORD-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase();
    }

    private void processOrderInternally(String orderId, OrderRequest orderRequest, BigDecimal totalAmount) {
        System.out.println("Processing Order ID: " + orderId);
        System.out.println("Customer: " + orderRequest.getCustomerName());
        System.out.println("Total Amount: $" + totalAmount);
        System.out.println("Items:");
        for (OrderItem item : orderRequest.getOrderItems()) {
            System.out.println("  - " + item.getItemName() + 
                             " (Qty: " + item.getQuantity() + 
                             ", Price: $" + item.getUnitPrice() + 
                             ", Line Total: $" + item.getLineTotal() + ")");
        }
    }

    private OrderResponse createErrorResponse(String errorMessage) {
        return new OrderResponse(
            null,
            "ERROR",
            errorMessage,
            BigDecimal.ZERO,
            new Date(),
            0
        );
    }
}